const I18n = (function(){
  let currentLang = "en";

  function setLang(code){
    currentLang = LANGS[code] ? code : "en";
    try{ localStorage.setItem("mindora_lang", currentLang); }catch(e){}
    document.documentElement.lang = currentLang;
    document.documentElement.dir = RTL_LANGS.includes(currentLang) ? "rtl" : "ltr";
    applyStaticTranslations();
  }

  function getLang(){ return currentLang; }

  function init(){
    let saved = "en";
    try{ saved = localStorage.getItem("mindora_lang") || "en"; }catch(e){}
    setLang(saved);
  }

  function t(key, vars){
    let str = (LANGS[currentLang] && LANGS[currentLang][key]) || (LANGS.en[key]) || key;
    if(vars){
      Object.keys(vars).forEach(k => {
        str = str.split("{" + k + "}").join(vars[k]);
      });
    }
    return str;
  }

  function applyStaticTranslations(){
    document.querySelectorAll("[data-i18n]").forEach(el => {
      el.textContent = t(el.getAttribute("data-i18n"));
    });
    document.querySelectorAll("[data-i18n-placeholder]").forEach(el => {
      el.placeholder = t(el.getAttribute("data-i18n-placeholder"));
    });
    document.querySelectorAll("[data-i18n-aria-label]").forEach(el => {
      el.setAttribute("aria-label", t(el.getAttribute("data-i18n-aria-label")));
    });
  }

  return { init, setLang, getLang, t, applyStaticTranslations };
})();
